record_types.code:
type Animation is
   record
      Id      :        Text;
      Name    :        Text;
      Sources : access library.Sources;
      Sampler :        animations.Sampler;
      Channel :        animations.Channel;
   end record;

type Channel is
   record
      Source : Text;
      Target : Text;
   end record;

type Item is
   record
      Contents : access Animation_array;
   end record;

type Sampler is
   record
      Id     : Text;
      Inputs : Inputs_view;
   end record;
